// "Post Note" -- text-only microblog note.
// Runs entirely here; this shortcut has no declared HTTP request of its own
// (it is a Scripting-type shortcut), so there is nothing after this script.

var noteText = getVariable('note_text');
if (noteText === null || noteText.trim() === '') {
  showToast('Post Note cancelled.');
  abort();
}

var now = new Date();
var slug = buildSlug(now);
var isoLocal = buildIsoLocal(now);

var markdown = '---\n'
  + 'date: ' + isoLocal + '\n'
  + '---\n'
  + noteText.trim() + '\n';

var path = 'src/views/notes/' + slug + '.md';
var url = 'https://api.github.com/repos/froggermtp/personal-site/contents/' + path;

var result = sendHttpRequest(url, {
  method: 'PUT',
  headers: githubHeaders(getVariable('github_token')),
  body: JSON.stringify({
    message: 'Add note ' + slug,
    content: base64encode(markdown),
    branch: 'main'
  })
});

if (result.status === 'success') {
  showToast('Note published: ' + slug);
} else {
  showDialog('Post Note failed.\n\n' + describeFailure(result), 'Post Note');
}

// "Post Photo Note" -- photo microblog note.
// This shortcut IS a Regular/HTTP shortcut (executionType "app") because
// only Regular shortcuts can declare a file parameter, which is what makes
// the app offer this shortcut in Android's image share sheet and populate
// `selectedFiles`. The declared request below (POST to the bare repo URL)
// is a harmless placeholder that is never actually meant to run -- all of
// the real work happens right here via sendHttpRequest(), and abort() at
// the end skips the declared request. It is left configured (rather than
// blank) as a safety net in case abort() ever fails to suppress it: it
// would just hit a GitHub endpoint that rejects POST with no side effects.

if (typeof selectedFiles === 'undefined' || selectedFiles.length === 0) {
  showToast('No image received.');
  abort();
}
var file = selectedFiles[0];

var noteText = getVariable('note_text');
var altText = getVariable('note_alt_text');
if (noteText === null || altText === null) {
  showToast('Post Photo Note cancelled.');
  abort();
}

// --- UNVERIFIED STEP: read the shared image as base64 ---
// 'base64' as a readFile() encoding argument is NOT enumerated in the
// public docs (which only confirm the default is UTF-8). This is the best
// documented-shaped guess and must be tested on-device before real use.
// See docs/phone-publishing.md for how to verify it and the fallback plan.
var dir = getDirectory();
var imageBase64 = dir.readFile(file.id, 'base64');

var now = new Date();
var slug = buildSlug(now);
var isoLocal = buildIsoLocal(now);
var headers = githubHeaders(getVariable('github_token'));
var apiBase = 'https://api.github.com/repos/froggermtp/personal-site/contents/';

// Images are always committed as .jpg per the site's content model.
// Share a JPEG for best results.
var imagePath = 'src/assets/images/notes/' + slug + '.jpg';
var imageResult = sendHttpRequest(apiBase + imagePath, {
  method: 'PUT',
  headers: headers,
  body: JSON.stringify({
    message: 'Add note image ' + slug,
    content: imageBase64,
    branch: 'main'
  })
});

if (imageResult.status !== 'success') {
  showDialog('Photo upload failed.\n\n' + describeFailure(imageResult), 'Post Photo Note');
  abort();
}

// Image committed successfully -- now commit the markdown that references
// it. Ordering matters: the site build reads the image file and fails if
// the markdown references one that doesn't exist yet on `main`.
var notePath = 'src/views/notes/' + slug + '.md';
var markdown = '---\n'
  + 'date: ' + isoLocal + '\n'
  + 'image: notes/' + slug + '.jpg\n'
  + 'imageAlt: "' + altText.trim().replace(/"/g, '\\"') + '"\n'
  + '---\n'
  + noteText.trim() + '\n';

var noteResult = sendHttpRequest(apiBase + notePath, {
  method: 'PUT',
  headers: headers,
  body: JSON.stringify({
    message: 'Add note ' + slug,
    content: base64encode(markdown),
    branch: 'main'
  })
});

if (noteResult.status === 'success') {
  showToast('Photo note published: ' + slug);
} else {
  showDialog(
    'Image uploaded, but the markdown commit failed.\n\n'
      + describeFailure(noteResult)
      + '\n\nThe image is already committed at ' + imagePath
      + ' -- you may need to add the note manually or retry.',
    'Post Photo Note'
  );
}

